# ================== EMBEDDED IMAGES (Base64) ==================
# base64 PNG data
KINETRIX_LOGO_B64 = """"""
KINETRIX_ICON_B64 = """"""

whole_color = "#292929"
secondary_color = "#393939"
ternary_color = "#191919"
alternate_color = "#dddddd"

def load_image_from_base64(b64_string, resize_to=None):
    """Decode base64 PNG to PIL image, optionally resize."""
    image_data = base64.b64decode(b64_string)
    image = Image.open(io.BytesIO(image_data))
    if resize_to:
        image = ImageOps.contain(image, resize_to)
    return image

class KinetrixSplash:
    def __init__(self, root, on_finish):
        self.root = root
        self.on_finish = on_finish
        self.splash = tk.Toplevel(root)
        self.splash.overrideredirect(True)
        self.splash.config(bg=whole_color)
        screen_w = self.splash.winfo_screenwidth()
        screen_h = self.splash.winfo_screenheight()
        w, h = 950, 500
        x = (screen_w // 2) - (w // 2)
        y = (screen_h // 2) - (h // 2)
        self.splash.geometry(f"{w}x{h}+{x}+{y}")
        self.splash.attributes("-alpha", 0.0)  # start fully transparent

        # Icon (fades in first, wobble)
        self.icon_img = load_image_from_base64(KINETRIX_ICON_B64, (300, 300))
        self.icon_photo = ImageTk.PhotoImage(self.icon_img)
        self.icon_label = tk.Label(self.splash, image=self.icon_photo, bg=whole_color)
        self.icon_label.place(relx=0.36, rely=0.4, anchor="center")

        # Full logo (hidden initially)
        self.logo_label = None

        # Roles frame (bottom)
        self.roles_frame = tk.Frame(self.splash, bg=whole_color)
        self.roles_frame.place(relx=0.5, rely=0.75, anchor="n")
        role_font = ("Tahoma", 14, "bold")
        fg_color = alternate_color
        top_roles = [("CEO", "ALEXIS MAXEY"), ("COO", "SPENCER PERRY"), ("CFO", "EVAN GALVIN")]
        bottom_roles = [("CTO", "TRENT ROSENTHAL"), ("CCO", "ALEX GOWOROWSKI"), ("CAO", "CONNOR McFADDEN")]
        for col, (title, name) in enumerate(top_roles):
            tk.Label(self.roles_frame, text=f"{title} - {name}", bg=whole_color, fg=fg_color,
                     font=role_font, anchor="w", justify="left").grid(row=0, column=col, padx=30, pady=6, sticky="w")
        for col, (title, name) in enumerate(bottom_roles):
            tk.Label(self.roles_frame, text=f"{title} - {name}", bg=whole_color, fg=fg_color,
                     font=role_font, anchor="w", justify="left").grid(row=1, column=col, padx=30, pady=6, sticky="w")

        self.icon_angle = 0
        self.icon_alpha = 0.0
        self.fade_in_icon()

    def fade_in_icon(self):
        if self.icon_alpha < 1.0:
            self.icon_alpha += 0.01
            self.splash.attributes("-alpha", self.icon_alpha)

            # Wobble icon
            self.icon_angle += (1 - self.icon_alpha) * 30
            angle_rad = np.radians(np.sin(self.icon_angle * np.pi / 180) * 5)
            rotated_img = self.icon_img.rotate(np.degrees(angle_rad), resample=Image.BICUBIC, expand=True)
            self.icon_photo = ImageTk.PhotoImage(rotated_img)
            self.icon_label.config(image=self.icon_photo)

            self.splash.after(5, self.fade_in_icon)
        else:
            # Icon fully visible, start fading in logo
            self.icon_label.place_forget()  # optionally hide icon
            self.icon_alpha = 1.0  # keep background fully visible
            self.fade_in_logo()

    def fade_in_logo(self):
        if self.logo_label is None:
            logo_img = load_image_from_base64(KINETRIX_LOGO_B64, (800, 300))
            self.logo_photo = ImageTk.PhotoImage(logo_img)
            self.logo_label = tk.Label(self.splash, image=self.logo_photo, bg=whole_color)
            self.logo_label.place(relx=0.5, rely=0.4, anchor="center")  # center logo

        if self.splash.attributes("-alpha") < 1.0:
            # Keep background at current opacity
            self.splash.attributes("-alpha", 1.0)
        self.logo_label.lift()  # ensure logo is on top

        self.splash.after(3600, self.fade_out_zoom)

    def fade_out_zoom(self):
        alpha = self.splash.attributes("-alpha")
        if alpha > 0.0:
            alpha -= 0.02
            self.splash.attributes("-alpha", alpha)
            self.splash.after(5, self.fade_out_zoom)
        else:
            self.splash.destroy()
            self.on_finish()




